"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9816],{823(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9","title":"Discourses \u2014 Book 2, Chapter 9","description":"Book 2 \u2014 Chapter 9","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":10,"frontMatter":{"sidebar_position":10,"title":"Discourses \u2014 Book 2, Chapter 9","sidebar_label":"Book 2, Ch. 9"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 8","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-8"},"next":{"title":"Book 2, Ch. 10","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-10"}}');var n=o(4848),i=o(8453);const a={sidebar_position:10,title:"Discourses \u2014 Book 2, Chapter 9",sidebar_label:"Book 2, Ch. 9"},r="Discourses",h={},d=[{value:"Book 2 \u2014 Chapter 9",id:"book-2--chapter-9",level:2},{value:"That We Adopt The Profession Of The Philosopher When We Cannot Fulfil That Of A Man",id:"that-we-adopt-the-profession-of-the-philosopher-when-we-cannot-fulfil-that-of-a-man",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(t.h2,{id:"book-2--chapter-9",children:"Book 2 \u2014 Chapter 9"}),(0,n.jsx)(t.h3,{id:"that-we-adopt-the-profession-of-the-philosopher-when-we-cannot-fulfil-that-of-a-man",children:"That We Adopt The Profession Of The Philosopher When We Cannot Fulfil That Of A Man"})]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.p,{children:"Man is a rational animal. The rational faculty distinguishes us from beasts and sheep. Act like a beast \u2014 combative, angry, reckless \u2014 and you destroy the man in you. Act like a sheep \u2014 following appetite, random and inconsiderate \u2014 and the same."}),(0,n.jsx)(t.p,{children:"The chapter's sting is in the closing: being unable to fulfill the basic calling of a man, we adopt the calling of philosopher \u2014 which is a heavier burden, not a lighter one. It's like someone who can't lift ten pounds trying to lift Ajax's boulder. Philosophical discourse without philosophical character isn't philosophy; it's performance. You can expound Stoic doctrine more fluently than Epictetus and still be a Jew acting Greek \u2014 someone performing an identity they haven't actually inhabited. The principles need to be digested, not stored."})]}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(t.h2,{id:"text",children:"Text"}),(0,n.jsx)(t.p,{children:"IT IS no ordinary task merely to fulfil man's promise. For what is Man? A rational animal, subject to death. At once we ask, from what does the rational element distinguish us? From wild beasts. And from what else? From sheep and the like. Look to it then that you do nothing like a wild beast, else you destroy the Man in you and fail to fulfil his promise. See that you do not act like a sheep, or else again the Man in you perishes."}),(0,n.jsx)(t.p,{children:"You ask how we act like sheep?"}),(0,n.jsx)(t.p,{children:"When we consult the belly, or our passions, when our actions are random or dirty or inconsiderate, are we not falling away to the state of sheep? What do we destroy? The faculty of reason. When our actions are combative, mischievous, angry, and rude, do we not fall away and"}),(0,n.jsx)(t.p,{children:"become wild beasts? In a word, some of us are great beasts, and others are small but base-natured beasts, which give occasion to say, 'Nay, rather let me be food for a lion.' All these are actions by which the calling of man is destroyed."}),(0,n.jsx)(t.p,{children:"What makes a complex proposition be what it is? It must fulfil its promise: it keeps its character only if the parts it is composed of are true. What makes a disjunctive proposition? It must fulfil its purport. Is not the same true of flutes, lyre, horse, and dog? Is it surprising then that man too keeps or loses his nature on the same principle? Each man is strengthened and preserved by the exercise of the functions that correspond to his nature, the carpenter by carpentering, the grammarian by studies in grammar. If a man gets the habit of writing ungrammatically, his art is bound to be destroyed and perish. In the same way the modest man is made by modest acts and ruined by immodest acts, the man of honour keeps his character by honest acts and loses it by dishonest. So again men of the opposite character are strengthened by the opposite actions: the shameless man by shamelessness, the dishonest by dishonesty, the slanderous by slander, the ill-tempered by ill-temper, the miser by grasping at more than he gives. That is why philosophers enjoin upon us 'not to be content with learning only, but to add practice as well and then training'. For we have acquired wrong habits in course of years and have adopted for our use conceptions opposite to the true, and therefore if we do not adopt true conceptions for our use we shall be nothing else but interpreters of judgements which are not our own."}),(0,n.jsx)(t.p,{children:"Of course any one of us can discourse for the moment on what is good and what is bad: as thus, 'Of things that are, some are good, some bad, some indifferent; good are virtues and things that have part in virtues; evil are the opposite; indifferent are wealth, health, reputation.' And then if some loud noise disturbs us while we are speaking or one of the bystanders laughs at us, we are put out of countenance. Philosopher, where are those principles you were talking of? Whence did you fetch them forth to utter? From the lips and no further."}),(0,n.jsx)(t.p,{children:"These principles are not your own: why do you make a mess of them? Why do you gamble with things of highest moment? It is one thing (to use an illustration) to put bread and wine away into a store-cupboard, and another thing to eat. What you eat is digested and distributed, and is turned into sinews, flesh, bones, blood, complexion, breath. What you store away you have at hand and can show to others at will, but it does you no good except for the mere name of having it. What is the good of expounding these doctrines any more than those of another school? Sit down now and discourse on the doctrines of Epicurus, and you will soon discourse more effectively than Epicurus"}),(0,n.jsx)(t.p,{children:"himself. Why then do you call yourself a Stoic, why do you deceive the world, why being a Hellene do you act the Jew?  Do you not see in what sense a man is called a Jew, in what sense a Syrian, in what an Egyptian? When we see a man trimming between two faiths we are wont to say, 'He is no Jew, but is acting a part', but when he adopts the attitude of mind of him who is baptized and has made his choice, then he is not only called a Jew but is a Jew indeed. So we also are but counterfeit 'baptists', Jews in name only, but really something else, with no feeling for reason, far from acting on the principles we talk of, though we pride ourselves on them as though we knew them. So, being unable to fulfil the calling of Man we adopt that of the Philosopher, a heavy burden indeed! It is as though one who could not lift ten pounds were fain to lift the stone of Ajax!"})]})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>r});var s=o(6540);const n={},i=s.createContext(n);function a(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);